{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class AnnotationRuleOfficialTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given multiple annotations before class constructor in ktlint_official code style`() {
        val code =
            """
            data class Foo @Bar1 @Bar2("bar") @Bar3 @Bar4 constructor(private val foobar: Int) {
                fun foo(): String = "foo"
            }
            """.trimIndent()
        val formattedCode =
            """
            data class Foo
                @Bar1
                @Bar2("bar")
                @Bar3
                @Bar4
                constructor(private val foobar: Int) {
                fun foo(): String = "foo"
            }
            """.trimIndent()
        annotationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .addAdditionalRuleProvider { IndentationRule() }
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a single annotation without parameters before a function in ktlint_official code style`() {
        val code =
            """
            @Bar fun foo() {}
            """.trimIndent()
        annotationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a single annotation with parameters before a function in ktlint_official code style`() {
        val code =
            """
            @Bar("bar") fun foo() {}
            """.trimIndent()
        val formattedCode =
            """
            @Bar("bar")
            fun foo() {}
            """.trimIndent()
        annotationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given multiple annotations on type projections in ktlint_official code style`() {
        val code =
            """
            val fooBar: FooBar<String, @Foo String, @Foo @Bar String, @Bar("bar") @Foo String> = FooBar()
            """.trimIndent()
        val formattedCode =
            """
            val fooBar: FooBar<
                String,
                @Foo String,
                @Foo @Bar
                String,
                @Bar("bar")
                @Foo
                String
                > = FooBar()
            """.trimIndent()
        annotationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .addAdditionalRuleProvider { IndentationRule() }
            .addAdditionalRuleProvider { WrappingRule() }
            .isFormattedAs(formattedCode)
    }
}
