        val nodeBeforeAnnotations =
            modifierListRoot
                .treeParent
                .treePrev
        // Make sure we only insert a single newline
        val indentWithoutNewline =
            nodeBeforeAnnotations
                ?.text
                .orEmpty()
                .let { text ->
                    if (text.contains('\n')) {
                        text.substringAfterLast('\n')
                    } else {
                        modifierListRoot
                            .treeParent
                            .indent()
                            .takeIf { modifierListRoot.treeParent.elementType == ElementType.PRIMARY_CONSTRUCTOR }
                            ?: text
                    }
                }
        return "\n".plus(indentWithoutNewline)
