import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import org.jetbrains.kotlin.com.intellij.lang.ASTNode

class DebugRule : Rule(RuleId("debug"), VisitorModifier.RunAsFirst) {
    override fun beforeVisitChildNodes(node: ASTNode, autoCorrect: Boolean, emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit) {
        println("${node.elementType}: ${node.text.take(20).replace("\n", "\\n")}")
    }
}

class PsiDebugTest {
    @Test
    fun dumpPsi() {
        val code = """
            data class Foo @Bar1 constructor(val x: Int)
        """.trimIndent()
